  app2.get("/api/facilities/:id/stock-balance", ...auth, async (req, res) => {
    try {
      const facilityId = parseInt(req.params.id);
      if (isNaN(facilityId)) {
        return res.status(400).json({ message: "Invalid facility ID" });
      }
      const txns = await storage.getStockTransactions(req.tenantId, facilityId);
      const balance = {};
      for (const t of txns) {
        const name = t.vaccineName;
        if (!balance[name]) balance[name] = 0;
        const qty = t.quantityDoses;
        if (t.transactionType === "receipt") {
          balance[name] += qty;
        } else if (t.transactionType === "issue") {
          balance[name] -= qty;
        } else if (t.transactionType === "loss") {
          balance[name] -= qty;
        } else if (t.transactionType === "adjustment") {
          balance[name] += qty;
        }
      }
      res.json(balance);
    } catch (error) {
      console.error("Error fetching stock balance:", error);
      res.status(500).json({ message: "Failed to fetch stock balance: " + error.message });
    }
  });
